import{_ as o,c as a,o as t,ai as s}from"./chunks/framework.C8-0bFZC.js";const _=JSON.parse('{"title":"NeoNephos Goals Document Release","description":"","frontmatter":{"title":"NeoNephos Goals Document Release","date":"2026-02-09","banner":"assets/blog/20260210_neonephos_goals_document_release.svg","authors":["neonephos-team"],"tags":["2026","news"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"BlogEntryThemeComponent"},"headers":[],"relativePath":"blog/20260210_neonephos_goals_document_release.md","filePath":"blog/20260210_neonephos_goals_document_release.md"}'),r={name:"blog/20260210_neonephos_goals_document_release.md"};function n(l,e,h,p,i,d){return t(),a("div",null,e[0]||(e[0]=[s('<h1 id="neonephos-goals-document-release" tabindex="-1">NeoNephos Goals Document Release <a class="header-anchor" href="#neonephos-goals-document-release" aria-label="Permalink to &quot;NeoNephos Goals Document Release&quot;">​</a></h1><p>On January 8th, the NeoNephos Governing Board got together for an in-person strategy workshop at SAP Walldorf. Great ideas were exchanged and a preliminary vision constructed for how we see NeoNephos in 2026. It was agreed on that one of the first items to do in 2026, was to further formalize our mission, who we are and how we fit into the bigger picture of European cloud native sovereignty. The day has come where we can finally share <a href="https://neonephos.org/goals" target="_blank" rel="noreferrer">this document to the world</a>!</p><p>The <a href="https://neonephos.org/goals" target="_blank" rel="noreferrer">goals document</a> supplements our mission statement in <a href="https://cdn.platform.linuxfoundation.org/agreements/neonephos-foundation.pdf?__hstc=81619592.11739e1f4ca03192f4e918409f725053.1748961872693.1755169332458.1755604645613.29&amp;__hssc=81619592.2.1755604645613&amp;__hsfp=1879682750" target="_blank" rel="noreferrer">our charter</a> and serves as a first point of reference for people aiming to understand our purpose.</p><p>It is a first in series of further documents to come, like descriptions of the project proposal process and more, which aim to get the community onboarded efficiently and getting our message across.</p><p>So without further ado, read through the goals document now:</p><p><strong><a href="https://neonephos.org/goals" target="_blank" rel="noreferrer">Goals Document</a></strong></p>',6)]))}const f=o(r,[["render",n]]);export{_ as __pageData,f as default};
